  private _controllerListeners: Set<string> = new Set();

  get switchCount(): number {
    return this._switches.size;
  }

  get flowCount(): number {
    let total = 0;
    for (const flows of this._flows.values()) {
      total += flows.length;
    }
    return total;
  }

  get history(): string[] {
    return [...this._history];
  }

  get sliceCount(): number {
    return this._networkSlices.size;
  }

  get qosClassCount(): number {
    return this._qosClasses.size;
  }

  get loadBalancerCount(): number {
    return this._loadBalancers.size;
  }

  get applicationCount(): number {
    return this._applications.size;
  }

