  private _counter = 0;
  private _networkSlices: Map<string, NetworkSlice> = new Map();
  private _qosClasses: Map<string, QoSClass> = new Map();
  private _loadBalancers: Map<string, LoadBalancerPool> = new Map();
  private _applications: Map<string, SDNApplication> = new Map();
  private _topologyLinks: TopologyLink[] = [];
  private _portStatus: Map<string, PortStatus[]> = new Map();
  private _flowStats: Map<string, FlowStats[]> = new Map();
  private _packetInHandlers: Map<string, (packet: unknown) => void> = new Map();
  private _controllerListeners: Set<string> = new Set();

  get switchCount(): number {
    return this._switches.size;
  }

  get flowCount(): number {
    let total = 0;
    for (const flows of this._flows.values()) {
      total += flows.length;
    }
    return total;
  }

  get history(): string[] {
    return [...this._history];
  }

  get sliceCount(): number {
    return this._networkSlices.size;
  }

  get qosClassCount(): number {
    return this._qosClasses.size;
  }

  get loadBalancerCount(): number {
    return this._loadBalancers.size;
  }

  get applicationCount(): number {
    return this._applications.size;
  }

  get linkCount(): number {
    return this._topologyLinks.length;
  }

  get controllerInfo(): SDNControllerInfo | null {
    return this._controller;
  }

  public controllerSetup(controller: string, switches: string[]): { controller: string; switches: number; connected: boolean } {
    this._controller = { name: controller, switches: switches.length, applications: 5, topology: 'tree', uptime: 0, version: '2.0.0' };
    switches.forEach(sw => {
      this._switches.set(sw, { id: sw, dpId: `dpid-${sw}`, flows: 0, ports: 8, status: 'connected', uptime: 0, manufacturer: 'OpenFlow Inc.', hardware: 'OF-Switch-100' });
      this._flows.set(sw, []);
      this._portStatus.set(sw, []);
      for (let i = 1; i <= 8; i++) {
        this._portStatus.get(sw)!.push({
          portId: i,
          name: `eth${i}`,
          status: 'up',
          speed: 1000,
          macAddress: `00:00:00:00:00:0${i}`,
          rxPackets: 0,
          txPackets: 0,
          rxBytes: 0,
          txBytes: 0,
        });
      }
    });
    this._recordHistory(`controllerSetup(${controller}, switches=${switches.length})`);
    return { controller, switches: switches.length, connected: true };
  }

  public openFlow(switchId: string, controller: string, version: string): { switch: string; controller: string; version: string; connected: boolean } {
    const sw = this._switches.get(switchId);
    if (sw) {
      this._switches.set(switchId, { ...sw, status: 'connected' });
    }
    this._recordHistory(`OpenFlow ${version}: ${switchId} <-> ${controller}`);
    return { switch: switchId, controller, version, connected: true };
  }

  public flowTable(switchId: string, flows: string[]): { switch: string; flows: number; tableSize: number; utilized: number } {
    const flowRules: FlowRule[] = flows.map((f, i) => ({
      id: `flow-${switchId}-${i}`,
      tableId: 0,
      priority: 100 + i,
      match: { pattern: f },
      actions: ['output'],
      idleTimeout: 60,
      hardTimeout: 300,
      cookie: i,
    }));
    this._flows.set(switchId, flowRules);
    const sw = this._switches.get(switchId);
    if (sw) {
      this._switches.set(switchId, { ...sw, flows: flows.length });
    }
    this._recordHistory(`flowTable(${switchId}): ${flows.length} flows`);
    return { switch: switchId, flows: flows.length, tableSize: 4096, utilized: flows.length / 4096 };
  }

